export default function Home() {
  const [carouselImages, setCarouselImages] = useState<CarouselImage[]>(defaultCarouselImages)
  const [services, setServices] = useState<Service[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchData = async () => {
      try {
        const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'
        
        // Try new API endpoints first
        try {
          const [carouselRes, servicesRes] = await Promise.all([
            fetch(`${apiUrl}/api/public/site`).catch(() => null),
            fetch(`${apiUrl}/api/public/programs/weekly`).catch(() => null)
          ])

          // If new API works, use it
          if (servicesRes) {
            const servicesData = await servicesRes.json()
            if (servicesData.success && servicesData.data) {
              setServices(servicesData.data.map((prog: any) => ({
                id: prog.id,
                name: prog.name,
                time: prog.time,
                day: prog.day,
                description: prog.description || ''
              })))
            }
          }
        } catch (error) {
          // Try old API endpoints as fallback
          try {
            const [carouselRes, servicesRes] = await Promise.all([
              fetch(`${apiUrl}/api/landing/carousel`).catch(() => null),
              fetch(`${apiUrl}/api/landing/services`).catch(() => null)
            ])

            if (carouselRes) {
              const carouselData = await carouselRes.json()
              if (carouselData.success && carouselData.data) {
                setCarouselImages(carouselData.data)
              }
            }

            if (servicesRes) {
              const servicesData = await servicesRes.json()
              if (servicesData.success && servicesData.data) {
                setServices(servicesData.data)
              }
            }
          } catch (oldApiError) {
            console.error('Error fetching from old API:', oldApiError)
          }
        }
      } catch (error) {
        console.error('Error fetching data:', error)
        // Keep default carousel images already set
      } finally {
        setLoading(false)
      }
    }

    fetchData()
  }, [])

  return (
    <main>
      <Header />
      <Carousel images={carouselImages} />
      
      {/* Watch Live & Join Prayer Section */}
      <section style={{
        background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 100%)',
        padding: '3rem 20px',
        textAlign: 'center'
      }}>
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
          <h2 style={{
            fontSize: '2.5rem',
            fontWeight: 700,
            color: '#FFD700',
            marginBottom: '1rem'
          }}>
            Join Us Online
          </h2>
          <p style={{
            fontSize: '1.2rem',
            color: 'rgba(255, 255, 255, 0.9)',
            marginBottom: '2rem'
          }}>
            Experience worship and prayer from anywhere
          </p>
          <div style={{
            display: 'flex',
            gap: '1.5rem',
            justifyContent: 'center',
            flexWrap: 'wrap'
          }}>
            <a
              href="/sermons"
              style={{
                background: '#DC143C',
                color: 'white',
                padding: '1rem 2.5rem',
                borderRadius: '6px',
                textDecoration: 'none',
                fontWeight: 700,
                fontSize: '1.1rem',
                transition: 'all 0.3s ease',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '0.5rem',
                boxShadow: '0 4px 10px rgba(220, 20, 60, 0.3)'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = '#B8122E'
                e.currentTarget.style.transform = 'translateY(-2px)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = '#DC143C'
                e.currentTarget.style.transform = 'translateY(0)'
              }}
            >
              <span>▶️</span>
              Watch Live
            </a>
            <a
              href="/sermons"
              style={{
                background: '#FFD700',
                color: '#1a1a2e',
                padding: '1rem 2.5rem',
                borderRadius: '6px',
                textDecoration: 'none',
                fontWeight: 700,
                fontSize: '1.1rem',
                transition: 'all 0.3s ease',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '0.5rem',
                boxShadow: '0 4px 10px rgba(255, 215, 0, 0.3)'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = '#FFA500'
                e.currentTarget.style.transform = 'translateY(-2px)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = '#FFD700'
                e.currentTarget.style.transform = 'translateY(0)'
              }}
            >
              <span>🙏</span>
              Join Prayer
            </a>
          </div>
          <div style={{ marginTop: '2rem' }}>
            <a
              href="/services"
              style={{
                color: 'white',
                textDecoration: 'none',
                fontSize: '1.1rem',
                fontWeight: 600,
                borderBottom: '2px solid #FFD700',
                paddingBottom: '0.25rem',
                transition: 'color 0.3s ease'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.color = '#FFD700'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.color = 'white'
              }}
            >
              Plan Your Visit / Join Us This Sunday →
            </a>
          </div>
        </div>
      </section>

      {loading ? (
        <div style={{ 
          display: 'flex', 
          justifyContent: 'center', 
          alignItems: 'center', 
          padding: '2rem',
          fontSize: '18px',
          color: '#666'
        }}>
          Loading services...
        </div>
      ) : (
        <Services services={services} />
      )}
      <CoreValues />
      <ContactSection />
      <Footer />
    </main>
  )
}
